// src/components/Sidebar.jsx
import { Link } from 'react-router-dom';

function Sidebar() {
  return (
    <aside className="w-64 h-[90vh] bg-white shadow-xl flex flex-col items-center px-4">
      {/* 상단 로고 */}
      <div className="flex items-center gap-2 text-blue-600 font-bold text-xl mb-8">
        <span>🏠</span>
        <span>Homeprotect</span>
      </div>

      {/* 메뉴 리스트 박스 */}
      <div className="w-full border border-blue-200 rounded-lg p-4 space-y-4 mb-6">
      <Link to="/" className="flex items-center gap-2 text-gray-800">
          <span>🏠</span> <span>시작하기</span>
        </Link>
        <div className="flex items-center gap-2 text-gray-800">
          <span>🗨️</span> <span>커뮤니티</span>
        </div>
        <Link to="/detect" className="flex items-center gap-2 text-gray-800">
          <span>🤖</span> <span>전세 사기</span>
        </Link>
        <div className="flex items-center gap-2 text-gray-800">
          <span>✉️</span> <span>소식</span>
        </div>
        <div className="flex items-center gap-2 text-gray-800">
          <span>✏️</span> <span>내 집 마련 가이드</span>
        </div>
      </div>

      {/* 로그인 버튼 */}
      <button className="w-full border border-blue-300 text-blue-600 px-4 py-2 rounded-lg hover:bg-blue-50">
        ⎆ Login
      </button>
    </aside>
  );
}

export default Sidebar;
